  "approval_timestamp" timestamptz,
  "hr_contact_id" uuid,
  "fmla_eligible_flag" boolean DEFAULT false,
  "notes" varchar(1000),
  "created_by" uuid NOT NULL,
  "creation_timestamp" timestamptz NOT NULL,
  "last_updated_by" uuid NOT NULL,
  "last_update_timestamp" timestamptz NOT NULL
);

CREATE TABLE "document" (
  "document_id" uuid PRIMARY KEY NOT NULL,
  "person_id" uuid NOT NULL,
  "employment_id" uuid,
  "document_type_id" integer NOT NULL,
  "document_name" varchar(200) NOT NULL,
  "document_version" int NOT NULL DEFAULT 1,
  "document_status_id" integer NOT NULL,
  "effective_date" date NOT NULL,
  "expiration_date" date,
  "storage_reference" varchar(500) NOT NULL,
  "file_format" varchar(20) NOT NULL,
  "upload_date" timestamptz NOT NULL,
  "uploaded_by" uuid NOT NULL,
  "verified_by" uuid,
  "verification_date" timestamptz,
  "superseded_by_document_id" uuid,
  "legal_hold_flag" boolean NOT NULL DEFAULT false,
  "created_by" uuid NOT NULL,
  "creation_timestamp" timestamptz NOT NULL
);

CREATE TABLE "document_download_audit" (
  "audit_id" uuid PRIMARY KEY,
  "document_id" uuid NOT NULL,
  "accessed_by" uuid NOT NULL,
  "access_timestamp" timestamptz NOT NULL
);

CREATE TABLE "person_social_profile" (
  "person_id" uuid PRIMARY KEY,
  "photo_data" bytea,
  "photo_mime_type" varchar(50),
  "bio_text" varchar(1000),
  "updated_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "work_queue_item" (
  "work_queue_item_id" uuid PRIMARY KEY,
  "item_type" varchar(50) NOT NULL,
  "reference_id" uuid NOT NULL,
  "reference_type" varchar(50) NOT NULL,
  "employment_id" uuid,
  "assigned_role" varchar(100) NOT NULL,
  "status" varchar(20) NOT NULL DEFAULT 'OPEN',
  "priority" varchar(20) NOT NULL DEFAULT 'NORMAL',
  "title" varchar(200) NOT NULL,
  "description" text,
  "due_date" date,
  "created_at" timestamptz NOT NULL,
  "resolved_at" timestamptz,
  "resolved_by" uuid
);

CREATE TABLE "onboarding_plan" (
  "onboarding_plan_id" uuid PRIMARY KEY NOT NULL,
  "employment_id" uuid NOT NULL,
  "plan_template_id" uuid,
  "plan_status_id" integer NOT NULL,
  "target_start_date" date NOT NULL,
  "completion_date" date,
  "assigned_hr_contact_id" uuid,
  "created_by" uuid NOT NULL,
  "creation_timestamp" timestamptz NOT NULL,
  "last_updated_by" uuid NOT NULL,
  "last_update_timestamp" timestamptz NOT NULL
);

CREATE TABLE "onboarding_task" (
  "task_id" uuid PRIMARY KEY NOT NULL,
  "onboarding_plan_id" uuid NOT NULL,
  "task_type_id" integer NOT NULL,
  "task_name" varchar(200) NOT NULL,
  "task_owner_role" varchar(100) NOT NULL,
  "task_owner_user_id" uuid,
  "due_date" date NOT NULL,
  "completion_date" date,
  "task_status_id" integer NOT NULL,
  "blocking_flag" boolean NOT NULL DEFAULT false,
  "waiver_reason" varchar(500),
  "waived_by" uuid,
  "created_by" uuid NOT NULL,
  "creation_timestamp" timestamptz NOT NULL
);

CREATE TABLE "leave_balance" (
  "leave_balance_id" uuid PRIMARY KEY NOT NULL,
  "employment_id" uuid NOT NULL,
  "leave_type_id" integer NOT NULL,
  "available_balance" decimal(10,4) NOT NULL DEFAULT 0,
  "pending_balance" decimal(10,4) NOT NULL DEFAULT 0,
  "used_balance" decimal(10,4) NOT NULL DEFAULT 0,
  "entitlement_total" decimal(10,4) NOT NULL DEFAULT 0,
  "plan_year_start" date NOT NULL,
  "plan_year_end" date NOT NULL,
  "last_accrual_date" date,
  "last_updated_run_id" uuid,
  "created_timestamp" timestamptz NOT NULL,
  "last_update_timestamp" timestamptz NOT NULL
);

CREATE TABLE "report_execution_history" (
  "execution_id" uuid PRIMARY KEY NOT NULL,
  "report_id" varchar(50) NOT NULL,
  "report_title" varchar(200) NOT NULL,
  "requested_by" uuid NOT NULL,
  "execution_status" varchar(20) NOT NULL,
  "parameters_json" text NOT NULL,
  "row_count" integer,
  "export_format" varchar(10),
  "storage_reference" varchar(500),
  "async_job_id" uuid,
  "started_at" timestamptz NOT NULL,
  "completed_at" timestamptz,
  "error_message" text,
  "created_timestamp" timestamptz NOT NULL,
  "last_update_timestamp" timestamptz NOT NULL
);

